  var comment_counter_controller_default = class extends Controller {
    static targets = ["textarea", "progressBar", "countDisplay"];
    connect() {
      this.MAX = 1500;
      this.updateCounter();
      this.textareaTarget.addEventListener("input", this.updateCounter.bind(this));
    }
    disconnect() {
      this.textareaTarget.removeEventListener("input", this.updateCounter.bind(this));
    }
    updateCounter() {
      const len = this.textareaTarget.value.length;
      const percent = len / this.MAX * 100;
      this.progressBarTarget.style.width = `${percent}%`;
      if (len < 769) {
        this.progressBarTarget.className = "progress-bar bg-success";
      } else if (len < 1107) {
        this.progressBarTarget.className = "progress-bar bg-warning";
      } else {
        this.progressBarTarget.className = "progress-bar bg-danger";
      }
      this.countDisplayTarget.textContent = `${len} / ${this.MAX}`;
      this.countDisplayTarget.className = len > this.MAX * 0.95 ? "text-danger" : "text-muted";
    }
  };

  // app/javascript/controllers/hello_controller.js
  var hello_controller_default = class extends Controller {
    connect() {
      this.element.textContent = "Hello World!";
    }
  };

  // app/javascript/controllers/shoutbox_controller.js
  var shoutbox_controller_default = class extends Controller {
    static targets = ["panel", "messages", "input"];
    toggle() {
      const body = this.bodyTarget;
      const isHidden = body.style.display === "none";
      body.style.display = isHidden ? "block" : "none";
      if (isHidden) {
        const header = document.getElementById("shoutbox-header");
        const y2 = header.getBoundingClientRect().top + window.scrollY - 20;
        window.scrollTo({ top: y2, behavior: "smooth" });
      }
    }
    submit(event) {
      event.preventDefault();
      const form = event.target;
      const input = this.inputTarget;
      if (input.value.trim() === "") return;
      fetch(form.action, {
        method: "POST",
        body: new FormData(form),
        headers: { "Accept": "text/vnd.turbo-stream.html" }
      }).then((response) => {
        if (response.ok) {
          input.value = "";
        }
      });
    }
    scrollToTop() {
      const messagesContainer = this.formTarget.closest(".shoutbox").querySelector(".messages") || document.querySelector(".shoutbox .messages");
      if (messagesContainer) {
        messagesContainer.scrollTop = 0;
      }
    }
  };

  // app/javascript/controllers/sidebar_controller.js
  var sidebar_controller_default = class extends Controller {
    static targets = ["grid", "button"];
    connect() {
      const hidden = localStorage.getItem("sidebarHidden") === "true";
      if (hidden) {
        this.gridTarget.classList.add("sidebar-hidden");
      }
    }
    toggle() {
      this.gridTarget.classList.toggle("sidebar-hidden");
      const isHidden = this.gridTarget.classList.contains("sidebar-hidden");
      localStorage.setItem("sidebarHidden", isHidden);
    }
  };

  // app/javascript/controllers/test_controller.js
  var test_controller_default = class extends Controller {
    connect() {
      console.log("Stimulus Test-Controller ist verbunden! \u{1F389}");
      console.log("Element:", this.element);
    }
  };

